import React, { useState, useEffect, useCallback } from 'react';

const Trader = () => {
  const [chartFiles, setChartFiles] = useState({
    primary: null,
    higher: null,
    entry: null,
  });

  const [isSingleChartMode, setIsSingleChartMode] = useState(true);

  const toggleMode = () => {
    setIsSingleChartMode(!isSingleChartMode);
  };

  const handleSubmit = () => {
    // Implement submission logic
  };

  const handleFileChange = useCallback((file, slot) => {
    setChartFiles((prevFiles) => ({
      ...prevFiles,
      [slot]: file,
    }));
  }, []);

  useEffect(() => {
    const handlePaste = (e) => {
      e.preventDefault();
      const items = (e.clipboardData || e.originalEvent.clipboardData).items;
      for (const item of items) {
        if (item.type.startsWith('image/')) {
          const file = item.getAsFile();
          if (file) {
            if (isSingleChartMode) {
              handleFileChange(file, 'primary');
            } else {
              if (!chartFiles.primary) handleFileChange(file, 'primary');
              else if (!chartFiles.higher) handleFileChange(file, 'higher');
              else if (!chartFiles.entry) handleFileChange(file, 'entry');
              else handleFileChange(file, 'primary');
            }
            break;
          }
        }
      }
    };

    window.addEventListener('paste', handlePaste);
    return () => window.removeEventListener('paste', handlePaste);
  }, [chartFiles, isSingleChartMode, handleFileChange]);

  return (
    <div>
      <button onClick={toggleMode}>
        {isSingleChartMode ? 'Switch to Multi Chart' : 'Switch to Single Chart'}
      </button>

      <div style={{ display: 'flex' }}>
        <ChartUploadSlot
          label="Primary Chart"
          file={chartFiles.primary}
          onFileChange={(file) => handleFileChange(file, 'primary')}
        />
        {!isSingleChartMode && (
          <ChartUploadSlot
            label="Higher Chart"
            file={chartFiles.higher}
            onFileChange={(file) => handleFileChange(file, 'higher')}
          />
        )}
        {!isSingleChartMode && (
          <ChartUploadSlot
            label="Entry Chart"
            file={chartFiles.entry}
            onFileChange={(file) => handleFileChange(file, 'entry')}
          />
        )}
      </div>

      <button onClick={handleSubmit}>Submit</button>
    </div>
  );
};

const ChartUploadSlot = ({ label, file, onFileChange }) => {
  const handleChange = (e) => {
    const file = e.target.files[0];
    onFileChange(file);
  };

  const handleDrop = (e) => {
    e.preventDefault();
    const file = e.dataTransfer.files[0];
    onFileChange(file);
  };

  const handleDragOver = (e) => {
    e.preventDefault();
  };

  return (
    <div
      style={{
        width: '200px',
        height: '200px',
        border: '1px dashed #ccc',
        margin: '10px',
        textAlign: 'center',
        padding: '20px',
      }}
      onDrop={handleDrop}
      onDragOver={handleDragOver}
    >
      <label>{label}</label>
      {file ? (
        <img src={URL.createObjectURL(file)} alt={label} style={{ maxWidth: '100%', maxHeight: '100%' }} />
      ) : (
        <>
          <p>Click to upload, drag & drop / paste (Ctrl+V)</p>
          <input type="file" onChange={handleChange} style={{ display: 'none' }} />
        </>


**Finalizing Paste Feature**

I'm now fully immersed in verifying the implementation and ensuring robustness. I'm rigorously testing diverse usage scenarios to confirm optimal handling of image pastes and concurrent text input within `Trader.tsx`, ensuring `handleFileChange` is invoked consistently. I'm focusing on user experience, and testing all scenarios.

